import{_ as t,c as a,o,ax as d}from"./chunks/framework.DHqKNX4U.js";const m=JSON.parse('{"title":"Legal Holds","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/legal-holds/index.md","filePath":"enterprise/legal-holds/index.md"}'),i={name:"enterprise/legal-holds/index.md"};function l(r,e,n,c,s,h){return o(),a("div",null,e[0]||(e[0]=[d('<h1 id="legal-holds" tabindex="-1">Legal Holds <a class="header-anchor" href="#legal-holds" aria-label="Permalink to &quot;Legal Holds&quot;">​</a></h1><p>The Legal Holds feature is an enterprise-grade eDiscovery and compliance mechanism designed to prevent the spoliation (destruction) of evidence. It provides <strong>absolute, unconditional immunity</strong> from deletion for archived emails that are relevant to pending litigation, regulatory investigations, or audits.</p><h2 id="core-principles" tabindex="-1">Core Principles <a class="header-anchor" href="#core-principles" aria-label="Permalink to &quot;Core Principles&quot;">​</a></h2><h3 id="_1-absolute-immunity-—-highest-precedence-in-the-lifecycle-pipeline" tabindex="-1">1. Absolute Immunity — Highest Precedence in the Lifecycle Pipeline <a class="header-anchor" href="#_1-absolute-immunity-—-highest-precedence-in-the-lifecycle-pipeline" aria-label="Permalink to &quot;1. Absolute Immunity — Highest Precedence in the Lifecycle Pipeline&quot;">​</a></h3><p>A legal hold is the final word on whether an email can be deleted. The <a href="./../retention-policy/lifecycle-worker.html">Lifecycle Worker</a> evaluates emails in a strict three-step precedence pipeline:</p><ol><li><strong>Step 0 — Legal Hold</strong> ← this feature</li><li>Step 1 — Retention Label</li><li>Step 2 — Retention Policy</li></ol><p>If an email is linked to <strong>at least one active</strong> legal hold, the lifecycle worker immediately flags it as immune and stops evaluation. No retention label or policy can override this decision. The <code>RetentionHook</code> mechanism also blocks any <strong>manual deletion</strong> attempt from the UI — the backend will return an error before any <code>DELETE</code> SQL is issued.</p><h3 id="_2-many-to-many-relationship" tabindex="-1">2. Many-to-Many Relationship <a class="header-anchor" href="#_2-many-to-many-relationship" aria-label="Permalink to &quot;2. Many-to-Many Relationship&quot;">​</a></h3><p>A single email can be placed under multiple holds simultaneously (e.g., one hold for a litigation case and another for a regulatory investigation). The email remains immune as long as <strong>any one</strong> of those holds is active. Each hold-to-email link is recorded independently with its own <code>appliedAt</code> timestamp and actor attribution.</p><h3 id="_3-active-inactive-state-management" tabindex="-1">3. Active/Inactive State Management <a class="header-anchor" href="#_3-active-inactive-state-management" aria-label="Permalink to &quot;3. Active/Inactive State Management&quot;">​</a></h3><p>Every hold has an <code>isActive</code> flag. When a legal matter concludes, the responsible officer deactivates the hold. The deactivation is instantaneous — on the very next lifecycle worker cycle, emails that were solely protected by that hold will be evaluated normally against retention labels and policies. If their retention period has already expired, they will be permanently deleted in that same cycle.</p><p>A hold <strong>must be deactivated before it can be deleted</strong>. This requirement forces an explicit, auditable act of lifting legal protection before the hold record can be removed from the system.</p><h3 id="_4-bulk-preservation-via-search-queries" tabindex="-1">4. Bulk Preservation via Search Queries <a class="header-anchor" href="#_4-bulk-preservation-via-search-queries" aria-label="Permalink to &quot;4. Bulk Preservation via Search Queries&quot;">​</a></h3><p>The primary use case for legal holds is casting a wide preservation net quickly. The bulk-apply operation accepts a full Meilisearch query (full-text search + metadata filters such as sender, date range, etc.) and links every matching email to the hold in a single operation. The system pages through results in batches of 1 000 to handle datasets of any size without timing out the UI.</p><h3 id="_5-gobd-audit-trail" tabindex="-1">5. GoBD Audit Trail <a class="header-anchor" href="#_5-gobd-audit-trail" aria-label="Permalink to &quot;5. GoBD Audit Trail&quot;">​</a></h3><p>Every action within the legal hold module — hold creation, modification, deactivation, deletion, email linkage, email removal, and bulk operations — is immutably recorded in the cryptographically chained <code>audit_logs</code> table. For bulk operations, the exact <code>SearchQuery</code> JSON used to cast the hold net is persisted in the audit log as proof of scope, satisfying GoBD and similar evidence-preservation requirements.</p><h2 id="feature-requirements" tabindex="-1">Feature Requirements <a class="header-anchor" href="#feature-requirements" aria-label="Permalink to &quot;Feature Requirements&quot;">​</a></h2><p>The Legal Holds feature requires:</p><ul><li>An active <strong>Enterprise license</strong> with the <code>LEGAL_HOLDS</code> feature enabled.</li><li>The <code>manage:all</code> permission for all hold management and bulk operations.</li><li>The <code>read:archive</code> permission for viewing holds applied to a specific email.</li><li>The <code>manage:all</code> permission for applying or removing a hold from an individual email.</li></ul><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><h3 id="active-litigation-hold" tabindex="-1">Active Litigation Hold <a class="header-anchor" href="#active-litigation-hold" aria-label="Permalink to &quot;Active Litigation Hold&quot;">​</a></h3><p>Upon receiving a litigation notice, a compliance officer creates a hold named &quot;Project Titan Litigation — 2026&quot;, applies it via a bulk query scoped to a specific custodian&#39;s emails and a date range, and immediately freezes those records. The audit log provides timestamped proof that the hold was in place from the moment of creation.</p><h3 id="regulatory-investigation" tabindex="-1">Regulatory Investigation <a class="header-anchor" href="#regulatory-investigation" aria-label="Permalink to &quot;Regulatory Investigation&quot;">​</a></h3><p>A regulator requests preservation of all finance-related communications from a specific period. The officer creates a hold and uses a keyword + date-range bulk query to capture every relevant email in seconds, regardless of which users sent or received them.</p><h3 id="tax-audit" tabindex="-1">Tax Audit <a class="header-anchor" href="#tax-audit" aria-label="Permalink to &quot;Tax Audit&quot;">​</a></h3><p>Before an annual audit window, an officer applies a hold to all emails matching tax-relevant keywords. The hold is released once the audit concludes, and standard retention policies resume.</p><h3 id="ediscovery-case-management" tabindex="-1">eDiscovery Case Management <a class="header-anchor" href="#ediscovery-case-management" aria-label="Permalink to &quot;eDiscovery Case Management&quot;">​</a></h3><p>Holds can optionally be linked to an <code>ediscovery_cases</code> record (<code>caseId</code> field) to organise multiple holds under a single legal matter. This allows all holds, emails, and audit events for a case to be referenced together.</p><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Location</th><th>Description</th></tr></thead><tbody><tr><td>Types</td><td><code>packages/types/src/retention.types.ts</code></td><td><code>LegalHold</code>, <code>EmailLegalHoldInfo</code>, <code>BulkApplyHoldResult</code> types</td></tr><tr><td>Database Schema</td><td><code>packages/backend/src/database/schema/compliance.ts</code></td><td><code>legal_holds</code> and <code>email_legal_holds</code> table definitions</td></tr><tr><td>Service</td><td><code>packages/enterprise/src/modules/legal-holds/LegalHoldService.ts</code></td><td>All business logic for CRUD, linkage, and bulk operations</td></tr><tr><td>Controller</td><td><code>packages/enterprise/src/modules/legal-holds/legal-hold.controller.ts</code></td><td>Express request handlers with Zod validation</td></tr><tr><td>Routes</td><td><code>packages/enterprise/src/modules/legal-holds/legal-hold.routes.ts</code></td><td>Route registration with auth and feature guards</td></tr><tr><td>Module</td><td><code>packages/enterprise/src/modules/legal-holds/legal-hold.module.ts</code></td><td>App-startup integration and <code>RetentionHook</code> registration</td></tr><tr><td>Frontend Page</td><td><code>packages/frontend/src/routes/dashboard/compliance/legal-holds/</code></td><td>SvelteKit management page for holds</td></tr><tr><td>Email Detail</td><td><code>packages/frontend/src/routes/dashboard/archived-emails/[id]/</code></td><td>Per-email hold card in the email detail view</td></tr><tr><td>Lifecycle Guard</td><td><code>packages/backend/src/hooks/RetentionHook.ts</code></td><td>Static hook that blocks deletion if a hold is active</td></tr></tbody></table><h2 id="data-model" tabindex="-1">Data Model <a class="header-anchor" href="#data-model" aria-label="Permalink to &quot;Data Model&quot;">​</a></h2><h3 id="legal-holds-table" tabindex="-1"><code>legal_holds</code> Table <a class="header-anchor" href="#legal-holds-table" aria-label="Permalink to &quot;`legal_holds` Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>uuid</code> (PK)</td><td>Auto-generated unique identifier.</td></tr><tr><td><code>name</code></td><td><code>varchar(255)</code></td><td>Human-readable hold name.</td></tr><tr><td><code>reason</code></td><td><code>text</code></td><td>Optional description of why the hold was placed.</td></tr><tr><td><code>is_active</code></td><td><code>boolean</code></td><td>Whether the hold currently grants immunity. Defaults to <code>true</code> on creation.</td></tr><tr><td><code>case_id</code></td><td><code>uuid</code> (FK)</td><td>Optional reference to an <code>ediscovery_cases</code> row.</td></tr><tr><td><code>created_at</code></td><td><code>timestamptz</code></td><td>Hold creation timestamp.</td></tr><tr><td><code>updated_at</code></td><td><code>timestamptz</code></td><td>Last modification timestamp.</td></tr></tbody></table><h3 id="email-legal-holds-join-table" tabindex="-1"><code>email_legal_holds</code> Join Table <a class="header-anchor" href="#email-legal-holds-join-table" aria-label="Permalink to &quot;`email_legal_holds` Join Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>email_id</code></td><td><code>uuid</code> (FK)</td><td>Reference to <code>archived_emails.id</code>. Cascades on delete.</td></tr><tr><td><code>legal_hold_id</code></td><td><code>uuid</code> (FK)</td><td>Reference to <code>legal_holds.id</code>. Cascades on delete.</td></tr><tr><td><code>applied_at</code></td><td><code>timestamptz</code></td><td>DB-server timestamp of when the link was created.</td></tr><tr><td><code>applied_by_user_id</code></td><td><code>uuid</code> (FK)</td><td>User who applied the hold (nullable for system operations).</td></tr></tbody></table><p>The table uses a composite primary key of <code>(email_id, legal_hold_id)</code>, enforcing uniqueness at the database level. Duplicate inserts use <code>ON CONFLICT DO NOTHING</code> for idempotency.</p><h2 id="integration-points" tabindex="-1">Integration Points <a class="header-anchor" href="#integration-points" aria-label="Permalink to &quot;Integration Points&quot;">​</a></h2><h3 id="retentionhook-deletion-guard" tabindex="-1">RetentionHook (Deletion Guard) <a class="header-anchor" href="#retentionhook-deletion-guard" aria-label="Permalink to &quot;RetentionHook (Deletion Guard)&quot;">​</a></h3><p><code>LegalHoldModule.initialize()</code> registers an async check with <code>RetentionHook</code> at application startup. <code>ArchivedEmailService.deleteArchivedEmail()</code> calls <code>RetentionHook.canDelete(emailId)</code> before any storage or database DELETE. If the email is under an active hold, the hook returns <code>false</code> and deletion is aborted with a <code>400 Bad Request</code> error. This guard is fail-safe: if the hook itself throws an error, deletion is also blocked.</p><h3 id="lifecycle-worker" tabindex="-1">Lifecycle Worker <a class="header-anchor" href="#lifecycle-worker" aria-label="Permalink to &quot;Lifecycle Worker&quot;">​</a></h3><p>The lifecycle worker calls <code>legalHoldService.isEmailUnderActiveHold(emailId)</code> as the first step in its per-email evaluation loop. Immune emails are skipped immediately with a <code>debug</code>-level log entry; no further evaluation occurs.</p><h3 id="audit-log" tabindex="-1">Audit Log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit Log&quot;">​</a></h3><p>All legal hold operations generate entries in <code>audit_logs</code>:</p><table tabindex="0"><thead><tr><th>Action</th><th><code>actionType</code></th><th><code>targetType</code></th><th><code>targetId</code></th></tr></thead><tbody><tr><td>Hold created</td><td><code>CREATE</code></td><td><code>LegalHold</code></td><td>hold ID</td></tr><tr><td>Hold updated / deactivated</td><td><code>UPDATE</code></td><td><code>LegalHold</code></td><td>hold ID</td></tr><tr><td>Hold deleted</td><td><code>DELETE</code></td><td><code>LegalHold</code></td><td>hold ID</td></tr><tr><td>Email linked to hold (individual)</td><td><code>UPDATE</code></td><td><code>ArchivedEmail</code></td><td>email ID</td></tr><tr><td>Email unlinked from hold</td><td><code>UPDATE</code></td><td><code>ArchivedEmail</code></td><td>email ID</td></tr><tr><td>Bulk apply via search</td><td><code>UPDATE</code></td><td><code>LegalHold</code></td><td>hold ID + query JSON</td></tr><tr><td>All emails released from hold</td><td><code>UPDATE</code></td><td><code>LegalHold</code></td><td>hold ID</td></tr></tbody></table><p>Individual email link/unlink events target <code>ArchivedEmail</code> so that a per-email audit search surfaces the complete hold history for that email.</p>',45)]))}const p=t(i,[["render",l]]);export{m as __pageData,p as default};
